import Foundationimport Combineimport FirebaseAuthclass AuthViewModel: ObservableObject {    @Published var user: User? = nil    @Published var errorMessage: String? = nil    @Published var isLoading: Bool = false    private var handle: AuthStateDidChangeListenerHandle?    init() {        handle = Auth.auth().addStateDidChangeListener { [weak self] _, user in            DispatchQueue.main.async {                self?.user = user            }        }    }    deinit {        if let handle { Auth.auth().removeStateDidChangeListener(handle) }    }    var isLoggedIn: Bool { user != nil }    @MainActor    func signUp(email: String, password: String) async {        isLoading = true        errorMessage = nil        do {            let result = try await Auth.auth().createUser(withEmail: email, password: password)            user = result.user        } catch {            errorMessage = error.localizedDescription        }        isLoading = false    }    @MainActor    func signIn(email: String, password: String) async {        isLoading = true        errorMessage = nil        do {            let result = try await Auth.auth().signIn(withEmail: email, password: password)            user = result.user        } catch {            errorMessage = error.localizedDescription        }        isLoading = false    }    func signOut() {        try? Auth.auth().signOut()        user = nil    }}